def sort_array(array):
    if len(array) <= 1:
        return list(array)
    first = array[0]
    last = array[-1]
    sum_fl = first + last
    if sum_fl % 2 == 1:
        return sorted(array)
    else:
        return sorted(array, reverse=True)
